import { test, expect } from '@playwright/test';

// standing red regression — will go green when it's fixed
// documents the gap: FinalReview fires family-graph flush, but executeFamilyGraphSync
// → backend v3 person/relationship → Neo4j → §25 aggregate fails to surface spouse+child.
test('§25 aggregate surfaces spouse and child after FinalReview flush', async ({ page }) => {
  await page.goto('/intake/abc-123/final-review');
  await page.click('button[data-action=flush]');
  await page.goto('/dashboard/firm/section-25');
  await expect(page.locator('[data-testid=person-row]')).toContainText('Jane Doe (spouse)');
  await expect(page.locator('[data-testid=person-row]')).toContainText('Sam Doe (child)');
});

